package com.example.lessondesign.dao; import com.example.lessondesign.bean.ECondition; import org.apache.ibatis.annotations.*; import java.util.*; @Mapper public interface EConditionDao { @Insert("INSERT INTO e_condition (exercise_id,u_id,score,submit_time,wrong_number,wrong_count,total_questions,correct_count,time_spent,submit_status) VALUES (#{exerciseId},#{uId},#{score},#{submitTime},#{wrongNumber},#{wrongCount},#{totalQuestions},#{correctCount},#{timeSpent},#{submitStatus})") @Options(useGeneratedKeys=true,keyProperty="id") int insert(ECondition e); @Select("SELECT * FROM e_condition WHERE u_id=#{sid}") List<ECondition> findByStudentId(@Param("sid") String sid); @Update("UPDATE e_condition SET teacher_comment=#{comment} WHERE id=#{id}") int updateTeacherComment(@Param("id") int id, @Param("comment") String comment); }